CREATE VIEW `ads_short_video_video_dl_log_view` (`id` COMMENT "自增id", `create_time` COMMENT "创建时间", `app_id` COMMENT "应用程序id", `appver` COMMENT "版本号", `chl` COMMENT "渠道值", `mt` COMMENT "终端", `core` COMMENT "corever", `row_data` COMMENT "行数据", `decrypt_data` COMMENT "加密数据", `unique_cdreader_id` COMMENT "唯一id", `current_language` COMMENT "语言id", `sdk` COMMENT "sdk", `region_id` COMMENT "地区id", `has_open` COMMENT "客户端上报isOpen,首次打开", `series_id` COMMENT "拉起短剧id", `defaultdl_Type` COMMENT "1029上报使用 归因类型 0:DL=0,1: UAC归因 2:IP+UA匹配，3 IP匹配 （归因判断条件就是 sdk=7时候 DefaultDLType 字段类型判断）", `sr_updatetime`, `sr_createtime`)
COMMENT "海外短剧自用归因日志查询" AS (SELECT `ods`.`ods_tidb_short_video_video_dl_log`.`id`, `ods`.`ods_tidb_short_video_video_dl_log`.`createtime` AS `create_time`, `ods`.`ods_tidb_short_video_video_dl_log`.`appid` AS `app_id`, `ods`.`ods_tidb_short_video_video_dl_log`.`appver`, `ods`.`ods_tidb_short_video_video_dl_log`.`chl`, `ods`.`ods_tidb_short_video_video_dl_log`.`mt`, `ods`.`ods_tidb_short_video_video_dl_log`.`core`, `ods`.`ods_tidb_short_video_video_dl_log`.`rowdata` AS `row_data`, `ods`.`ods_tidb_short_video_video_dl_log`.`decryptdata` AS `decrypt_data`, `ods`.`ods_tidb_short_video_video_dl_log`.`uniquecdreaderid` AS `unique_cdreader_id`, `ods`.`ods_tidb_short_video_video_dl_log`.`currentlanguage` AS `current_language`, `ods`.`ods_tidb_short_video_video_dl_log`.`sdk`, `ods`.`ods_tidb_short_video_video_dl_log`.`regionid` AS `region_id`, `ods`.`ods_tidb_short_video_video_dl_log`.`HasOpen` AS `has_open`, `ods`.`ods_tidb_short_video_video_dl_log`.`SeriesId` AS `series_id`, `ods`.`ods_tidb_short_video_video_dl_log`.`DefaultDLType` AS `defaultdl_Type`, `ods`.`ods_tidb_short_video_video_dl_log`.`sr_updatetime`, `ods`.`ods_tidb_short_video_video_dl_log`.`sr_createtime`
FROM `ods`.`ods_tidb_short_video_video_dl_log`);